INSERT INTO "public"."icps" ("id", "name", "description", "industry", "company_size", "location", "pain_points", "goals", "budget", "decision_makers", "tech_stack", "challenges", "opportunities", "created_at", "updated_at", "user_id", "collection_id", "circle_color", "color", "age_range", "avatar_key", "gender", "brand_id") VALUES
	('3cc9bd32-0ca8-483d-9ec0-efae8ab36300', 'ICP 1', 'Independently owned restaurants where the chef or owner cares about consistent high-heat performance and presentation. They need a durable wok that holds heat through service, supports larger batch cooking, and reduces replacement cycles compared to cheaper cookware.', 'Restaurants (independent, single-location to small multi-location)', '10–60 employees; 1–5 locations', 'Urban centers and food hubs in the US/Canada/UK/AU', '{"Carbon steel woks and lower-grade pans warp or thin out under heavy service and aggressive cleaning","Inconsistent heat when the line is slammed causes steaming instead of searing","Handles loosen, rivets fail, or cookware becomes unsafe under high-frequency use","New staff struggle with pan performance variability, impacting speed and consistency","Buying premium cookware for a restaurant feels risky without durability proof and service-use testimonials"}', '{"Maintain consistent sear and stir-fry throughput during peak service without pans losing heat","Reduce cookware replacement frequency caused by warping, handle loosening, or coating failure","Improve dish consistency across cooks by using a stable, heat-retentive super size wok","Support higher-volume prep (batch aromatics, sauces, proteins) with a larger wok capacity","Create a signature ''wok-fired'' menu item that photographs well for social and local marketing"}', '$400–$1,500 initial (2–6 woks + optional accessories); $1,500–$5,000/year if rolling replacements across stations', '{Chef-Owner,"Executive Chef","General Manager","Operations Manager (for multi-location)","Purchasing/Procurement (if present)"}', '{Instagram,TikTok,"Square / Toast POS","Google Workspace","DoorDash/Uber Eats merchant portals (common)","Canva or Adobe Express (menu/social assets)"}', '{"Proving ROI versus cheaper woks (replacement rate, consistency, speed) in a cost-sensitive environment","Ensuring the wok fits their burner setup and line workflow (wok ring, gas output, induction compatibility)","Managing expectations about seasoning and upkeep in a commercial dishwashing/cleaning routine"}', '{"Create a restaurant case study: ''90-day service test'' (heat retention, durability, throughput) with a local chef partner","Offer a ''line-ready'' bundle: super size wok + wok ring + care/seasoning protocol for staff training","Run targeted IG outreach to restaurants posting wok dishes, offering a demo unit or discounted second unit","Co-marketing: feature chef recipes and behind-the-scenes service clips to build credibility and drive DTC demand"}', '2025-12-16 22:15:01.449+00', '2025-12-17 11:56:40.1134+00', 'bf859676-aeb9-40f5-a5fa-77e55cf0df90', NULL, '#FFE69B', '#FF6B6B', NULL, NULL, NULL, NULL),
	('bd428e93-4461-4266-969e-0d0147b778b1', 'Toddler Parent in Suburban California Managing Bedtime Battles', 'Parent of a 18–48 month toddler who resists bedtime, asks for ''one more story,'' and wakes at night; wants a calming, repeatable story + sound routine that reduces negotiation and helps the child stay in bed.', 'Consumer (Parents & Families)', 'N/A (Individual household)', 'United States — California (Orange County, Sacramento area, Inland Empire, Silicon Valley suburbs)', '{"Toddler escalates at lights-out (crying, bargaining, leaving room repeatedly)","Parents feel guilty setting boundaries and end up extending bedtime nightly","Night wakings lead to co-sleeping by default, disrupting everyone’s sleep","External noise (traffic, siblings, pets) wakes the child and restarts the cycle","Screens before bed worsen settling but are used as a last resort"}', '{"Cut bedtime from 60–90 minutes of stalling to a 20–30 minute routine","Reduce repeated requests for extra stories by using a predictable story package","Help toddler stay in bed and fall back asleep without parent re-entry","Lower nighttime wake-ups caused by fear/darkness/sudden noises","Improve household evenings so parents can have 1–2 hours of downtime"}', 'USD $40–$150 for a family story package and companion sound routines; open to USD $10–$25/month if it replaces other bedtime purchases and reduces wake-ups', '{Mother,Father/partner,"Occasionally: nanny/babysitter influences what routine is followed"}', '{"Smartphone/tablet for audio playback","Facebook app (local parent groups, Reels, Ads)","Smart speaker (Amazon Echo/Google Nest) or dedicated nursery sound machine","Home Wi-Fi","Streaming audio app (Spotify/Apple Music) or direct download player"}', '{"Consistency: different caregivers run bedtime differently","Toddler’s preference changes quickly; boredom with the same story","Sibling noise and shared rooms complicate a calm sleep environment","Transitions (travel, daycare naps) throw off nighttime schedule"}', '{"Promote themed story sets (e.g., ''Brave Bedtime,'' ''Calm Down After Big Feelings'')","Use Facebook video ads showing a step-by-step toddler bedtime routine","Provide a ''bedtime boundary'' script paired with the story package","Create quick-access tracks for middle-of-the-night resettling (no talking needed)"}', '2026-01-09 14:55:26.984+00', '2026-01-09 14:55:26.984+00', 'b9f43ab4-a714-432a-843f-4b6bb6ef3891', NULL, NULL, NULL, NULL, NULL, NULL, 'a72f7a2b-71f4-469c-b8fc-4ab4a2c3420a'),
	('e69f75d2-eed7-48bc-a9d6-c2438a5149fa', 'Wall Street & Finance Professionals Seeking Perfect Fit', 'High-earning finance professionals who want premium, made-to-measure jeans that look sharp in business-casual settings and travel well, without spending time on in-store tailoring.', 'Financial Services (Investment Banking, Asset Management, Private Equity, Hedge Funds)', '500–10,000 employees', 'United States — New York, NY (Manhattan)', '{"Off-the-rack jeans fit thighs but gap at the waist (or fit waist but bind at thighs)","Inconsistent sizing across premium denim brands leads to returns and wasted time","Tailoring adds extra steps and cost, and results still vary between tailors","Need jeans that look refined (no loud distressing) yet comfortable for long workdays","Shipping/returns friction makes online denim purchases feel risky"}', '{"Get jeans that fit athletic legs or slim waist-to-thigh ratios without waist gapping","Build a polished business-casual wardrobe that pairs with blazers, shirts, and premium sneakers/loafers","Reduce time spent shopping by reordering the same perfect fit online","Avoid post-purchase tailoring and the trial-and-error of premium denim sizing","Find a consistent dark indigo/black jean suitable for Friday office wear and dinners"}', 'USD $250–$450 per pair; USD $800–$1,500 per year for denim refresh/reorders', '{"Individual buyer (Managing Director/VP/Associate)","Spouse/partner influencing style and purchase timing"}', '{iPhone,Instagram,Facebook,"Apple Pay","Shop Pay",Gmail}', '{"Limited availability for fittings/measurements due to long hours","Skepticism about made-to-measure accuracy without an in-person appointment","Needs quick turnaround for upcoming travel, events, or client dinners","Wants understated premium branding and fabric quality proof"}', '{"Offer a fast, guided measurement flow with fit guarantee and easy remakes","Retargeting on Instagram/Facebook using ''waist gap'' and ''athletic fit'' creatives","Promote reorder convenience (saved measurements, 1-click reorders) for repeat purchases","Position dark indigo/black as ''client-ready'' denim with minimal branding"}', '2025-12-29 17:09:23.237+00', '2025-12-29 17:09:23.237+00', 'b9f43ab4-a714-432a-843f-4b6bb6ef3891', NULL, NULL, NULL, NULL, NULL, NULL, '498645dd-41d3-4e20-9f0c-291e130dafe3'),
	('2380b32e-1846-4bd2-9f12-39d47526b195', 'Working Parent in California Seeking Reliable Sleep for Daycare Schedule', 'Busy working parent with an infant or toddler who needs consistent sleep to match daycare drop-offs and work demands; values convenience, fast setup, and routines that travel between home, grandparents, and trips.', 'Consumer (Parents & Families)', 'N/A (Individual household)', 'United States — California (Los Angeles, San Jose, Oakland, San Diego, Fresno)', '{"Child’s sleep gets worse after daycare due to overtiredness and late naps","Parents don’t have time to research or test multiple sleep methods","Travel and split households break routines and cause regressions","Noise differences between environments (grandparents, hotels, apartment living) cause wake-ups","Parent burnout from balancing work performance and frequent night interruptions"}', '{"Get the child asleep on schedule to protect morning wake time for daycare","Reduce early-morning wake-ups (before 5:30–6:00 AM) that derail workdays","Create a portable bedtime routine that works at home, hotels, and grandparents’ house","Minimize parent time spent troubleshooting sleep so evenings can be used for chores/work","Increase sleep consistency across weeknights and weekends"}', 'USD $50–$200 for a dependable story + white noise + lullaby routine solution; willing to spend USD $20–$60 for travel-friendly accessories or additional story packs', '{"Primary working parent (mom or dad)",Co-parent/partner,"Occasionally: grandparent caregiver (influences adherence to routine)"}', '{"iPhone or Android smartphone","Facebook (ads, parenting communities, local recommendations)","AirPods or small portable speaker","Smart speaker or sound machine at home","Calendar/reminders and baby sleep tracking app"}', '{"Keeping bedtime consistent when work runs late or commutes are long","Aligning naps with daycare schedule to prevent overtired nights","Ensuring caregivers follow the same audio routine and volume settings","Managing regressions (teething, illness) without starting over each time"}', '{"Position the family story package as a ''same routine anywhere'' sleep anchor","Offer downloadable/offline access for travel and spotty Wi-Fi","Create daycare-friendly wind-down tracks for pre-bed calm after busy days","Run Facebook retargeting for parents engaging with daycare and working-parent content"}', '2026-01-09 14:55:27.099+00', '2026-01-09 14:55:27.099+00', 'b9f43ab4-a714-432a-843f-4b6bb6ef3891', NULL, NULL, NULL, NULL, NULL, NULL, 'a72f7a2b-71f4-469c-b8fc-4ab4a2c3420a'),
	('9fa1b845-e16a-4fed-bddd-df77500aa808', 'New-to-Home-Education Creative Parent (Primary Years)', 'A parent who has recently started home education for a child aged 5–10 and wants a supportive UK community plus ready-to-use, design-led lessons that feel engaging and doable without a teaching background.', 'B2C (Home education / Parenting)', 'Home Schoolers', 'United Kingdom (England, Scotland, Wales, Northern Ireland)', '{"Overwhelmed by too many UK curriculum options and unsure what is ‘enough’ at home","Spends hours on Pinterest/YouTube gathering activities that don’t form a coherent progression","Worries they’re missing key skills (phonics, handwriting, basic maths) while trying to keep learning enjoyable","Child resists worksheets; parent needs hands-on, visually appealing projects that still teach core skills","Feels isolated and second-guesses decisions without a trusted community of UK parents"}', '{"Find a clear weekly rhythm for home education without replicating school at home","Use design-based projects to build confidence in literacy and numeracy through making","Reduce lesson planning time to under 2 hours per week using structured curriculum resources","Create a consistent portfolio of the child’s work for personal tracking and local authority conversations if needed","Connect with other UK home educators for encouragement, ideas, and accountability"}', 'GBP 10–25/month for a membership; up to GBP 30/month during term time if resources reduce planning stress', '{"Primary caregiving parent (mum or dad)","Co-parent/partner who approves recurring subscriptions"}', '{"Facebook Groups","Facebook Messenger",WhatsApp,"Google Drive",Canva,YouTube}', '{"Turning scattered activity ideas into a consistent learning plan","Maintaining motivation and routine during winter months and busy family periods","Adapting projects for different ages if teaching multiple children","Balancing screen time with meaningful, hands-on learning"}', '{"Promote ‘done-for-you’ weekly design-led lesson paths with minimal prep lists","Offer UK-friendly guidance on learning goals and how to document progress simply","Run Facebook live ‘plan with me’ sessions and printable project packs to drive trials","Create onboarding that helps them pick a starting level and build a 4-week routine fast"}', '2026-01-07 20:53:20.175+00', '2026-01-08 20:33:44.260964+00', 'b9f43ab4-a714-432a-843f-4b6bb6ef3891', NULL, NULL, '#4D96FF', NULL, NULL, NULL, '498645dd-41d3-4e20-9f0c-291e130dafe3'),
	('741137dc-bc12-431a-a0c5-5c25d91097a9', 'Avatar Test', 'Home chefs who cook 4–7 nights/week and want a forever-quality, handmade cast iron wok for high-heat searing, stir-fries, and one-pan meals. They follow cooking creators and buy premium cookware online when they see proof (results, durability, seasoning performance).', 'E-commerce (DTC cookware) / Home cooking', 'Solo consumer / household', 'United States, Canada, United Kingdom, Australia (metro/suburban)', '{"Nonstick woks/pans scratch, degrade, and can’t handle sustained high heat without failing","Thin carbon-steel woks warp on electric/induction or develop uneven heat zones","Unsure which wok size is truly big enough for 3–6 servings without crowding and steaming food","Confusion about seasoning and maintenance; fear of rust or sticky seasoning","Buying cookware online feels risky without clear proof of weight, handle comfort, and heat performance"}', '{"Get restaurant-quality stir-fry and sear at home using a super size wok without warping or hot spots","Own a single ''buy-it-for-life'' wok that replaces multiple pans and works for family-sized portions","Cook with high heat and develop a reliable seasoning layer that becomes more nonstick over time","Find a wok that feels stable and safe to handle when tossing food (balanced weight, secure handle)","Improve weeknight cooking speed: one-pan meals with fast cleanup and fewer dishes"}', '$150–$350 one-time purchase; will pay up to $450 for a handmade, lifetime-quality wok with accessories', '{"Primary home cook","Spouse/partner (shared household budget)"}', '{Instagram,TikTok,"Shopify store checkout","Apple Pay / Google Pay","Klaviyo (email/SMS)","Afterpay/Klarna (buy-now-pay-later)"}', '{"Educating on cast iron wok benefits vs carbon steel (heat retention, durability) without scaring people about weight","Overcoming maintenance objections (seasoning, cleaning) and fear of ''high effort cookware''","Showing real cooking outcomes on common home setups (gas, electric coil, glass-top, induction with adapter)"}', '{"TikTok/IG Reels series: ''Super Size Wok Weeknight'' (5 meals, 15 minutes each) demonstrating sear and portion capacity","Proof-driven creative: side-by-side comparisons (thin wok vs cast iron) showing warping, heat retention, and crust formation","Bundled starter kit: wok + seasoning wax/oil + metal spatula + care card to reduce maintenance anxiety","UGC program with home cooks showing first 30 days of seasoning progression and cleanup routines"}', '2025-12-17 12:24:02.31+00', '2025-12-18 10:25:23.148301+00', 'bf859676-aeb9-40f5-a5fa-77e55cf0df90', NULL, '#FFE69B', '#6BCB77', '18-24', 'female/18-24/female_18-24_003.png', 'female', NULL),
	('a25b537f-60b8-4bc0-a25d-f5ec5b7bddf8', 'Luxury Lifestyle', 'High-income professionals in fashion-adjacent, media, and creative leadership roles who care about silhouette and craftsmanship, and want made-to-measure denim that complements elevated streetwear and smart layering.', 'Media, Advertising, Fashion, Entertainment, Luxury Retail', '50–5,000 employees', 'United States — New York, NY (SoHo/Tribeca/Upper West Side)', '{"Jeans that pull at the crotch/hip or sag at the seat ruin the look of an outfit","Inseam and leg opening inconsistencies make styling with boots or heels difficult","Dislike mass-market branding; wants subtle, refined finishing","Frustration with tailoring: inconsistent results and extra appointments","Need confidence that made-to-measure will match the intended aesthetic (not just measurements)"}', '{"Achieve a precise silhouette (clean seat, correct rise, ideal taper) that photographs well","Get premium denim that complements designer outerwear and footwear","Own signature jeans that can transition from client meetings to nightlife","Ensure fit consistency across multiple fabrics/washes using saved measurements","Reduce wardrobe clutter by replacing multiple imperfect jeans with 1–2 perfect pairs"}', 'USD $300–$550 per pair; USD $1,000–$2,000 per year for curated denim rotation', '{"Individual buyer (Creative Director/Executive/Producer)","Stylist/Personal shopper influencing fabric, wash, and silhouette choices"}', '{iPhone,Instagram,Facebook,"Apple Pay","Shop Pay","Pinterest (style inspiration)"}', '{"High expectations for craftsmanship, fabric hand-feel, and finishing details","Needs visual proof of fit on diverse bodies and styling examples","Prefers personalized guidance but still wants the convenience of ecommerce","Wants dependable lead times for events, shoots, and travel"}', '{"Launch a concierge-style fit consult (DM or short call) and curated fabric recommendations","Use Instagram ads highlighting ''photograph-ready fit'' and silhouette control (rise/taper/leg opening)","Offer limited-run fabrics/washes with pre-order windows to create exclusivity","Partner with NYC stylists/designers for co-branded drops and referral campaigns"}', '2025-12-29 21:09:56.075+00', '2025-12-30 19:27:18.520769+00', 'b9f43ab4-a714-432a-843f-4b6bb6ef3891', NULL, NULL, '#FFD93D', NULL, 'female/25-34/female_25-34_003.png', NULL, '3aa3975b-cf18-4768-a6f2-d72abfc812f4'),
	('9826a18b-65f5-491b-abee-02e85a2585ec', 'California Boutique Wellness Retail Buyer', 'Small retail operator focused on curated, premium wellness products (independent grocery, juice bar, yoga studio café, boutique market). Needs differentiated fermented fizzy drinks that sell-through quickly and align with clean-label expectations.', 'Retail (Specialty Grocery / Wellness Retail / Café)', '1–10 employees (single location) or 10–50 employees (2–6 locations)', 'United States — California (statewide: Bay Area, Los Angeles, San Diego, Sacramento)', '{"Fermented beverages often have slow sell-through due to niche taste profiles","Refrigerated space is limited; every SKU must justify its slot with repeat purchase","Customers ask about sugar content and live cultures; staff needs simple talking points","Inconsistent distributor availability or minimum orders make ordering difficult","Sampling is costly but often necessary to convert first-time buyers"}', '{"Add a high-velocity functional beverage that complements existing wellness offerings","Increase average basket size with a premium refrigerated grab-and-go option","Stock a fermented drink with approachable flavor for mainstream customers (not overly tart)","Differentiate from national brands with a story, local relevance, and strong merchandising support","Maintain reliable restocks and predictable margins on beverage sets"}', 'USD $500–$3,000 per month for fermented/functional beverage purchasing (typical opening order USD $300–$1,200; ongoing restocks USD $200–$800/week depending on foot traffic)', '{Owner-operator,"Store manager","Retail buyer/merchandiser","Café/juice bar manager (if applicable)"}', '{"Square POS","Shopify (if offering online ordering)","Instagram (store marketing)","Facebook (local community posts)","Google Sheets (inventory planning)","Email ordering with suppliers/distributors"}', '{"Educating customers quickly at shelf without overwhelming them with probiotic jargon","Managing cold-chain logistics and minimizing spoilage risk","Forecasting demand spikes during promos, weekends, and seasonal health trends"}', '{"Provide retail-ready shelf talkers: ''low sugar,'' ''fermented for gut health,'' flavor notes, and FAQ","Offer in-store sampling kits and promo bundles to drive trial and repeat purchase","Local California co-marketing: Instagram collaborations, geo-targeted ads driving to stockists","Wholesale incentives: case discounts, guaranteed reorder windows, and best-selling flavor recommendations"}', '2025-12-28 18:24:24.826+00', '2025-12-29 19:59:13.391972+00', 'b9f43ab4-a714-432a-843f-4b6bb6ef3891', NULL, NULL, '#6BCB77', NULL, NULL, NULL, NULL),
