	('9477d915-324a-43b4-905e-d9fa78cf716f', 'Reseller-First Vintage Curator', 'A solo online reseller who sources unique secondhand clothing and needs consistent, photogenic inventory that performs on Pinterest and converts on their website or marketplace listings.', 'Resale / eCommerce (secondhand apparel)', '1–3 (solo founder + occasional contractor)', 'United States — West Coast (Los Angeles, San Diego, Orange County, Bay Area)', '{"Inconsistent thrift inventory quality and sizing makes it hard to keep a cohesive shop aesthetic","Time lost sorting, washing, photographing, and measuring low-quality pieces that won’t sell","Unpredictable costs and margins when sourcing item-by-item locally","Struggles to find pieces that are both unique and ‘Pinterestable’ enough to drive saves and clicks","High return risk due to unclear fit/condition details from suppliers"}', '{"Source 30–120 saleable vintage/secondhand clothing items per month with consistent margins","Build Pinterest traffic by pinning new drops (10–30 pins/week) that match trending aesthetics (workwear, cottagecore, 90s, normcore)","Reduce time spent thrift-hunting by buying pre-curated bundles that fit their shop niche","Increase average order value by selling coordinated sets (tops + bottoms, outerwear + accessories)","Maintain a steady upload cadence (5–20 new listings/week) without inventory gaps"}', 'USD 400–2,500/month for wholesale-style bundles or curated lots (plus shipping)', '{Owner/Reseller,"Shop Manager (when applicable)"}', '{"Shopify or Etsy","Pinterest Business",Canva,"Google Sheets","Pirate Ship or ShipStation","Instagram (secondary)"}', '{"Balancing inventory volume with storage constraints in small apartments or shared spaces","Standardizing product descriptions, measurements, and condition grading to reduce returns","Competing with larger resellers on price while maintaining uniqueness","Keeping consistent brand photography with limited time and equipment"}', '{"Offer niche-specific bundles (e.g., ‘West Coast Workwear’, ‘Festival Set’, ‘90s Denim’) optimized for Pinterest keywords","Provide ready-to-list items with measurements/condition notes to cut processing time","Create limited-time drops and ‘mystery boxes’ that encourage repeat purchases","Co-market with Pinterest boards and landing pages tailored to reseller niches"}', '2026-01-15 14:46:20.086+00', '2026-02-09 13:37:04.807135+00', 'b9f43ab4-a714-432a-843f-4b6bb6ef3891', NULL, NULL, '#4D96FF', NULL, NULL, NULL, NULL),
	('d6221181-5a1b-4a70-8dbe-df96a541edd8', 'Nostalgic Millennial Parent (Ages 28–40) with Primary-School Kids', 'UK-based millennial parent who remembers Stretch Armstrong or loves 80s/90s retro brands and wants a fun, physical toy for a child aged 5–9. Shops online, responds well to short-form video demos and parent-to-parent recommendations on Instagram.', 'Consumer (Parents / Family households)', 'Household (1–2 adults; 1–3 children)', 'United Kingdom (England: Greater Manchester, West Midlands, West Yorkshire; Scotland: Glasgow/Edinburgh; Wales: Cardiff area)', '{"Unsure if the toy will actually stretch to 6ft in real life or if the product images are exaggerated","Worries the toy will tear, leak, or break quickly with rough play","Concern about safety and suitability (age-appropriate strength/elasticity, materials, and supervision needs)","Overwhelmed by generic toy options; wants something that stands out at parties and playdates","Hates surprise shipping costs and unclear delivery times close to birthdays/Christmas"}', '{"Buy a birthday/Christmas gift that feels ''iconic'' and different from another screen-based present for a 5–9 year old","Find a toy that creates immediate ''wow'' (arms stretching up to 6ft) that the child will show friends","Choose a product that looks durable enough for repeat play without breaking after a few uses","Get fast, reliable UK delivery and clear gift-ready packaging","Keep the gift within a sensible per-child spend while still feeling premium"}', 'GBP 25–45 per toy (GBP 60–120 total seasonal gift budget per child)', '{"Mum (primary buyer)","Dad/partner (co-decision maker for budget and safety)","Grandparent occasionally influencing final choice"}', '{Instagram,Facebook,"Meta Shops","Shopify/WooCommerce storefronts (as a shopper)","Apple Pay/Google Pay","Royal Mail/Evri tracking links"}', '{"Differentiating Stretch Armstrong from cheaper stretchy knockoffs in a fast scroll environment","Building trust quickly with clear proof (real stretch length, durability, reviews) before price comparison kicks in","Handling last-minute gifting windows where delivery reliability is decisive","Managing parent concerns about mess, breakage, or unsafe play"}', '{"Use UGC/Reels showing the full 6ft stretch with a tape measure and child-safe play guidance","Bundle offers for siblings (e.g., 2-toy deal) and timed promotions for birthdays/Christmas","Retargeting ads to parents who watched 50%+ of demo videos with review-led creatives","Leverage nostalgia creatives (retro vibe) paired with modern parenting benefits: screen-free, active play"}', '2026-04-07 14:03:00.859+00', '2026-04-07 14:03:00.859+00', 'b9f43ab4-a714-432a-843f-4b6bb6ef3891', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
	('7c9d9521-c5e9-4a8a-b2f4-facf78c7d954', 'Practical Value-Seeking Family Shopper (Ages 30–45) in Suburban UK', 'UK suburban parent managing a busy household and looking for a reliable, good-value toy that keeps kids entertained without screens. Responds to clear pricing, delivery certainty, and straightforward proof of quality on Meta Ads and Facebook/Instagram.', 'Consumer (Parents / Family households)', 'Household (2 adults; 2–4 children common)', 'United Kingdom (Suburban commuter belts: Kent/Essex/Hertfordshire, Surrey, Lancashire, Nottinghamshire, Bristol area)', '{"Skeptical of paid-social toy ads due to past disappointments (cheap plastic, misleading claims)","Needs clarity on what’s included (size, materials, how far it stretches, care instructions)","Worries about arguments or unsafe tug-of-war play between siblings if the toy is too tempting to pull","Finds it hard to judge real-world durability from studio photos","Concerned about hidden costs: postage, returns, or accessories not included"}', '{"Find a toy that occupies kids aged 4–10 during weekends/after school and reduces screen time","Buy something robust enough to survive sibling play and not become ''broken in a day''","Get a fair price and avoid buyer’s remorse from low-quality impulse purchases","Secure quick UK delivery with tracking and simple returns if needed","Stretch the family gift budget across multiple children (birthdays, party gifts, stocking fillers)"}', 'GBP 20–35 per toy (GBP 80–150 monthly discretionary spend for kids’ treats and gifts)', '{"Parent/guardian who does the weekly household spending (often Mum)","Second parent approving bigger seasonal spends","Occasional influence from older sibling or the child via wish-list requests"}', '{Facebook,Instagram,"Meta Ads click-to-website","Price comparison via Google search",PayPal,"Klarna/Clearpay (if offered)"}', '{"Convincing value-seekers that a branded Stretch Armstrong is worth more than generic stretchy toys","Reducing purchase anxiety with strong review coverage and clear policies (returns, delivery, warranty)","Communicating safety and supervised play guidelines without killing excitement","Maintaining conversion when shoppers are highly price-sensitive and compare across retailers"}', '{"Create comparison creatives: ''Why the real Stretch Armstrong'' (materials, stretch distance, durability) with honest disclaimers","Offer multi-buy pricing and free shipping thresholds in GBP to lift AOV","Use FAQ-first landing pages: age guidance, stretch length proof, durability testing clips","Run retargeting with social proof: UK parent reviews, delivery speed, hassle-free returns"}', '2026-04-07 14:03:00.859+00', '2026-04-07 14:03:00.859+00', 'b9f43ab4-a714-432a-843f-4b6bb6ef3891', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
	('87f8d496-ad7d-45e8-9abb-b2c3d3242edf', 'Gift-Giver Grandparent/Aunt/Uncle (Ages 45–70) Buying for UK Kids', 'UK-based grandparent or relative buying a memorable gift for a child aged 4–9, often for birthdays, Christmas, or a reward. Less trend-driven, more trust-driven: wants recognisable hero branding, clear safety info, and dependable delivery.', 'Consumer (Gift buyers)', 'Household (often separate from recipient’s household)', 'United Kingdom (Nationwide; higher concentration in England and Scotland towns and cities)', '{"Not sure which toys kids actually like today; fears buying something that ends up unused","Confusion from too many online options and unclear product details","Worries about scams or unreliable sellers when purchasing from social ads","Needs simple, large-print clarity on age range, safety notes, and returns","Last-minute buying stress: needs accurate UK delivery estimates and tracking"}', '{"Give a ''proper toy'' that feels exciting and different, not another generic gadget","Choose a gift that the child will immediately play with and proudly show others (6ft stretch feature)","Feel confident about safety, quality, and age suitability before purchasing","Buy from a trusted checkout with clear delivery times to arrive before the occasion","Stay within a sensible gift amount while still giving something that feels special"}', 'GBP 25–50 per gift (GBP 100–250 seasonal gift budget across multiple grandchildren/nieces/nephews)', '{"Grandparent (primary buyer)","Aunt/uncle (primary buyer)","Parent of the child (influencer for approval on safety/appropriateness)"}', '{Facebook,"Instagram (light usage)","Meta Ads to website","Email (order confirmations)","Debit/credit card checkout","Trustpilot/Google Reviews (for reassurance)"}', '{"Building credibility quickly for a buyer who is more cautious about social-commerce","Reducing friction for less tech-confident shoppers (checkout, delivery info, returns)","Answering safety/quality questions clearly without requiring deep scrolling or extra research"}', '{"Run ''perfect gift'' creatives featuring gift wrap/boxing, clear age guidance, and delivery cut-off dates for the United Kingdom","Add prominent trust signals: verified reviews, clear returns policy, UK customer support contact","Create simple explainer videos with on-screen text: ''Stretches up to 6ft'' + ''How to play safely''","Offer occasion-specific bundles (birthday bundle, Christmas bundle) with straightforward GBP pricing"}', '2026-04-07 14:03:00.859+00', '2026-04-07 14:03:00.859+00', 'b9f43ab4-a714-432a-843f-4b6bb6ef3891', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
	('8877e2f4-b56a-4709-b0ef-b6fc03ef4e48', 'Weather-Damage Responder (Urgent Replacement)', 'United Kingdom homeowner dealing with active gutter failure (storm damage, sagging, leaks/overflow) who needs fast assessment and replacement to prevent further property damage, with clear pricing and quick installation.', 'Residential Homeowner', 'Household (1 property)', 'United Kingdom (nationwide; areas prone to heavy rain/wind exposure)', '{"Water pouring over gutter edges during rainfall despite ‘clearing’ them","Gutters pulling away from fascia boards or visibly sagging","Previous patch repairs failing within months","Concern that blockages will return due to nearby trees and moss","Stress of coordinating contractors quickly after bad weather","Fear of escalating repair bills if water damage spreads"}', '{"Stop active leaks/overflow immediately to prevent damp and internal staining","Replace damaged sections with a robust, seamless system that won’t split at joints","Ensure correct fall and outlet positioning so downpipes take water away efficiently","Get a firm, written quote and a quick installation date","Avoid repeat callouts by choosing a durable, 30+ year powder-coated finish"}', 'GBP 1,200–3,800 for replacement and remedial works; GBP 300–900 additional if new aluminium downpipes are required', '{Homeowner,Co-homeowner/partner,"Landlord (if the property is tenanted but the owner is arranging works)"}', '{"Facebook local groups","Meta Ads click-to-call","Email for quote/booking confirmation","Google Maps/Reviews checking (research step)","Smartphone photos/video for remote pre-assessment"}', '{"Identifying a contractor who can respond quickly and still provide quality workmanship","Understanding whether fascia/soffit repairs are needed before new gutters go up","Access and safety constraints requiring ladders/scaffolding on short notice","Sorting out drainage issues when existing downpipes are undersized, damaged, or poorly positioned"}', '{"Position a ‘rapid quote + fast fit’ funnel via Meta Ads with clear lead times","Offer optional leaf grid upsell to prevent repeat overflow calls","Create urgency-focused creatives: ‘Stop overflow before it becomes damp/rot’","Provide a simple checklist and photo guide for customers to send measurements and problem areas"}', '2026-04-15 15:15:22.217+00', '2026-04-15 15:17:22.872346+00', '3d065808-3338-43b1-8bfd-50660bbf83e5', NULL, NULL, NULL, NULL, 'female/25-34/female_25-34_005.png', NULL, NULL),
	('4c53e319-79e1-4936-9c8c-cf73ef56ccf9', 'Small-to-Mid Home Builder / Renovation Contractor (Reliable Trade Partner)', 'UK-based residential builder or renovation contractor managing multiple projects per year who needs dependable, consistent-quality seamless aluminium guttering installs with colour matching, predictable scheduling, and trade-friendly communication.', 'Residential Construction & Renovation', '5–50 employees', 'United Kingdom (regional builders working within 50–150 miles of project sites)', '{"Sectional systems leaking at joints leading to warranty issues and reputational risk","Last-minute delays from subcontractors that disrupt handover dates","Difficulty sourcing consistent colours that match windows/doors/trim across plots","Client complaints about gutters needing repainting or frequent cleaning","Complex rooflines on extensions requiring custom lengths and clean transitions to downpipes","Time lost coordinating multiple suppliers for gutters and downpipes"}', '{"Deliver a premium exterior finish that differentiates builds/refurbs (seamless lines, colour-matched gutters/downpipes)","Reduce snagging and callbacks caused by leaking joints or poorly aligned falls","Hit build programme dates with an installer who can slot into project schedules","Offer buyers a low-maintenance solution (30+ year coating, no repainting) as a selling point","Standardise a supplier for guttering and optional aluminium downpipes across multiple sites"}', 'GBP 5,000–30,000 per year across multiple projects; GBP 1,000–4,500 per plot depending on specification', '{"Company owner/director","Project manager","Site manager","Quantity surveyor (for procurement approval)"}', '{"Facebook/Instagram for supplier discovery","Meta Ads lead forms","Email (Microsoft 365/Google Workspace)","WhatsApp for site coordination","Project scheduling tools (e.g., Microsoft Project/Trello)"}', '{"Coordinating installs around scaffolding strike dates and other trades","Maintaining consistent spec and finish across multiple properties","Managing buyer selections for gutter colour and downpipe style late in the build","Ensuring drainage compliance and correct discharge points without redesigning late-stage"}', '{"Create a trade partner offer: priority scheduling, standardised colour range, and rapid quoting","Provide site-ready comms (RAMS/insurance details on request) to make procurement easier","Offer a spec sheet highlighting seamless aluminium benefits (no joints, long-life coating, colour stability)","Run retargeting ads to builders/contractors who engage with project photo case studies and testimonial content"}', '2026-04-15 15:15:22.217+00', '2026-04-15 15:17:30.251431+00', '3d065808-3338-43b1-8bfd-50660bbf83e5', NULL, NULL, NULL, NULL, 'female/25-34/female_25-34_008.png', NULL, NULL),
	('205b7ea1-5db2-4b18-85b3-f319d38da55a', 'Forever-Home Upgrader', 'Owner-occupier of a detached/semi-detached home in the United Kingdom who is planning exterior upgrades and wants a long-life, maintenance-free guttering solution (seamless aluminium, colour-matched, optional leaf grid).', 'Residential Homeowner', 'Household (1 property)', 'United Kingdom (England, Scotland or Wales; suburban and semi-rural areas)', '{"Repeated leaks at gutter joints and corners after heavy rain","Overflowing gutters causing water to run down walls and into foundations","Annual/seasonal gutter clearing is messy, time-consuming, or unsafe at height","Gutters look tired or mismatched after years of repainting or discolouration","Worry about hidden rot to fascias/soffits from persistent water issues","Uncertainty about whether new guttering can connect cleanly to existing downpipes"}', '{"Replace failing uPVC/cast-iron gutters with seamless aluminium that won’t leak at joints","Choose a colour (black, brown, white, cream, green, grey) that matches fascias/brickwork and improves kerb appeal","Stop recurring gutter cleaning by adding a leaf grid (especially near trees)","Prevent damp patches, staining, and overflow that damages render/brickwork and landscaping","Get an install completed quickly with minimal disruption and clear aftercare/warranty expectations"}', 'GBP 1,500–4,500 per property depending on linear metres, access and downpipe requirements', '{Homeowner,Co-homeowner/partner}', '{Facebook,Instagram,"Meta Ads","Email (Gmail/Outlook)","WhatsApp or phone calls for quotes"}', '{"Comparing like-for-like quotes (seamless aluminium vs sectional alternatives) and understanding what’s included","Scheduling installation around work hours and weather windows","Access constraints (conservatories, extensions, narrow side passages) affecting install complexity","Choosing colours confidently without seeing real examples on similar homes"}', '{"Offer a simple ‘No more painting’ + ‘No more cleaning’ package (powder-coated aluminium + leaf grid)","Use before/after photos and colour swatches to reduce hesitation and speed decisions","Promote connection to existing downpipes as a cost-saving option, with upgrade paths to new aluminium pipes","Retarget Meta ad clickers with testimonials focused on leak elimination and reduced maintenance"}', '2026-04-15 15:15:22.217+00', '2026-04-15 19:05:43.560314+00', '3d065808-3338-43b1-8bfd-50660bbf83e5', NULL, NULL, '#FFD93D', NULL, 'female/25-34/female_25-34_004.png', NULL, 'baf429f9-153d-47f7-9706-df6ff90ef0c6');
INSERT INTO "public"."icp_strategies" ("id", "icp_id", "user_id", "goal", "channel", "offer_type", "tone", "strategy", "prompt_version", "model", "created_at", "updated_at", "strategy_name") VALUES
	('097a9146-1d70-4c17-915f-0a8f0c6ae125', '741137dc-bc12-431a-a0c5-5c25d91097a9', 'bf859676-aeb9-40f5-a5fa-77e55cf0df90', 'Generate qualified leads', 'Email', 'Audit', 'Friendly', '{"offer": {"lead_magnet_idea": "2-minute “Wok Fit Check” quiz with instant results + a 7-night super-size wok meal plan email series.", "recommended_offer": "Free “Wok Fit & Seasoning Audit” (10–15 minutes): personalised size recommendation, hob/setup check, and a simple seasoning + cleanup routine based on your cooking habits.", "landing_page_sections": ["Who this audit is for (4–7 nights/week home cooks; 3–6 servings; high-heat cooking)", "What you’ll get (size recommendation, setup compatibility, seasoning plan, mistakes to avoid)", "How it works (3 steps, time required, what you need to share)", "Proof cues to include (short clips/photos: sear, portion capacity, cleanup, seasoning progression)", "Booking form + quiz link (capture email first)", "FAQs (weight, induction/glass-top, rust, sticky seasoning, returns/shipping)"]}, "ad_assets": {"headlines": ["Wok Size Help for 3–6 Servings", "Stop Crowding Your Stir-Fry", "High-Heat Cooking Without Warping", "Seasoning Made Simple (No Stress)", "Free Wok Fit & Seasoning Audit"], "primary_texts": ["Cooking 4–7 nights/week? Get a personalised wok size and setup recommendation, plus a simple seasoning routine you can stick to. Free 10–15 minute audit.", "If your stir-fry steams instead of searing, it’s usually pan size + heat performance. Take the 2-minute Wok Fit Check and we’ll recommend a better setup.", "Worried about rust or sticky seasoning? We’ll show the minimum-care routine and what to do if it goes wrong. Book a free audit."], "creative_briefs": ["UGC-style: home cook cooks a crowded stir-fry in a small pan vs roomy wok; overlay: “3–6 servings? Don’t steam it.” CTA to quiz.", "Proof clip: close-up of sear/crust + quick thermometer/heat retention moment; overlay: “High heat, stable results.” CTA to audit.", "Tutorial teaser: 15-second cleanup (wipe, rinse, dry, oil); overlay: “Seasoning doesn’t have to be hard.” CTA to audit.", "Handling demo: lift/toss with secure grip; overlay: “Stable feel matters.” CTA to quiz."]}, "messaging": {"value_props": ["Restaurant-style stir-fry at home: high heat, better browning, less steaming", "One pan that can replace multiple pans for weeknight speed and fewer dishes", "Reliable heat retention for consistent cooking across batches", "Seasoning that improves over time (more release, easier cleanup) when done simply", "Confidence buying online: clear guidance on size, weight feel and setup compatibility"], "pain_to_promise": ["Nonstick fails at high heat → A durable wok built for sustained heat and searing", "Warping and hot spots → A thicker, heat-retaining option with more stable performance", "Unsure which size to buy → A quick size-and-portion check based on your household and meals", "Seasoning anxiety → A simple 10-minute plan plus troubleshooting for stickiness/rust worries", "Online purchase risk → A personalised recommendation based on your hob, cooking style and comfort with weight"], "objections_and_rebuttals": ["“Cast iron is too heavy.” → We’ll assess your comfort level and suggest handling techniques and when a smaller size or helper handle matters.", "“Seasoning sounds like a faff.” → We provide a minimal routine (cook, wipe, dry, oil) and a simple reset method if it goes wrong.", "“Will it work on my induction/glass-top?” → We’ll review your setup and share safe options (including adapter use where appropriate).", "“I’m worried it won’t be big enough.” → We’ll map your usual portions and ingredients to the right diameter and depth to avoid steaming.", "“I don’t want a wok that rusts.” → We’ll outline storage and drying habits that prevent rust, plus what to do if you spot it."]}, "positioning": {"why_us": "We help you choose the right wok size and setup for your hob, then show simple seasoning and care so you get fast weeknight meals and better results with less guesswork.", "one_liner": "A forever-quality handmade cast iron wok for home cooks who want proper high-heat stir-fries and sears without warping or hot spots.", "differentiators": ["Proof-led results (sear, stir-fry, heat retention) shown on common home hobs", "Designed for big portions (3–6 servings) without crowding", "Seasoning made simple with clear steps and realistic expectations", "Stable, safer handling focus (balance, secure handle) to support tossing"]}, "channel_plan": {"first_14_days": ["Day 1–2: Build a 10-question “Wok Fit Check” quiz (hob type, portion size, confidence with weight, meals cooked, budget) and connect to Klaviyo.", "Day 3–4: Create 2 opt-in landing pages: (1) Wok Fit Check audit (2) 7-night plan; add pop-up and quiz embed on product pages.", "Day 5–6: Write core email flow (5 emails): results + recommendation, proof email, seasoning basics, setup tips by hob type, CTA to book audit.", "Day 7: Publish 3 short videos (portion capacity demo, sear close-up, quick cleanup) and drive to quiz link in bio.", "Day 8–10: Send broadcast to new leads: “Reply with your hob + servings” for manual triage; book audits via a simple scheduler.", "Day 11–14: Add 2 segmented follow-ups (induction/glass-top vs gas; 3–4 servings vs 5–6 servings) with tailored tips and audit CTA."], "primary_channel": "Email", "secondary_channels": ["Instagram Reels", "TikTok", "On-site quiz + pop-up", "SMS (post-opt-in reminders)"]}, "campaign_ideas": [{"cta": "Take the 2-minute Wok Fit Check", "hook": "Not sure which wok size and setup will actually work at home?", "name": "Wok Fit Check (Email Lead)", "angle": "Short audit to match portion size, hob type and handling comfort to the right wok and routine."}, {"cta": "Get the 7-night plan", "hook": "Cook 5–7 nights/week? Get a week of 15-minute wok dinners.", "name": "7-Night Stir-Fry Plan (Email Series)", "angle": "Opt-in to a 7-email plan with shopping list, high-heat tips and cleanup routine."}, {"cta": "Join the 30-day seasoning challenge", "hook": "Make seasoning feel easy in 30 days.", "name": "Seasoning Confidence Challenge", "angle": "Email prompts with day 1 seasoning, week 1 expectations, and quick fixes for sticky spots."}, {"cta": "See the results", "hook": "See what happens when thin woks meet high heat.", "name": "Warp Test Proof Drop", "angle": "Email with side-by-side results and what it means for your cooking outcomes."}], "success_metrics": {"kpis": ["Email opt-in conversion rate (quiz/landing pages)", "Audit bookings per week", "Lead-to-purchase rate within 14–30 days", "Email engagement (open rate, click rate)", "Qualified lead rate (meets budget + cooks 4–7 nights/week)"], "targets": ["Quiz/landing page opt-in: 4–8% of visitors", "Audit booking rate from new leads: 5–12%", "Lead-to-purchase: 3–8% within 30 days", "Email click rate: 1.5–3.5%", "Qualified leads: 60–75% of audit bookings"]}}', 'icp_strategy_v1', 'gpt-5.2', '2026-01-29 22:04:15.219+00', '2026-01-29 22:04:15.219+00', 'Strategy 1'),
	('ab1f1d36-598c-493c-a5a5-5be2ac0d0379', '9477d915-324a-43b4-905e-d9fa78cf716f', 'b9f43ab4-a714-432a-843f-4b6bb6ef3891', 'Increase conversions', 'LinkedIn organic', 'Consultation', 'Friendly', '{"offer": {"lead_magnet_idea": "One-page ‘Pinterestable Drop Spec’ template: aesthetics, size range, condition rules, set-building guide, and keyword list.", "recommended_offer": "30-minute Reseller Sourcing & Drop Strategy Consultation (friendly, practical plan for inventory targets, bundle spec, pricing and drop cadence).", "landing_page_sections": ["Who it’s for (solo resellers; 30–120 items/month goal)", "What you’ll get (bundle spec, margin targets, drop cadence plan, return-reduction checklist)", "How it works (intake questions + 30-min call + follow-up notes)", "Proof signals (generic examples: sample bundle spec, anonymised before/after metrics)", "Pricing + booking CTA (calendar link)"]}, "ad_assets": null, "messaging": {"value_props": ["Cut sourcing time with pre-curated lots that match your shop niche", "Improve conversion with clearer fit/condition info and more cohesive drops", "Boost AOV by building coordinated sets from complementary pieces", "Reduce return risk with consistent grading and measurement standards"], "pain_to_promise": ["Thrift trips are unpredictable → Predictable monthly bundles within your budget and storage limits", "Too many duds to process → Higher hit-rate bundles with clear condition standards", "Hard to find ‘Pinterestable’ pieces → Aesthetic-led curation aligned to trending keywords", "Returns due to fit/condition → Standardised measurements and condition notes per item"], "objections_and_rebuttals": ["“Curated bundles are too expensive.” → Compare cost per saleable item and time saved; start with a small pilot bundle and track margin/time.", "“I’m worried the style won’t match my shop.” → Use a quick ‘shop aesthetic’ intake (top keywords, colours, silhouettes) and approve a mini sample set first.", "“Condition issues will cause returns.” → Agree grading rules upfront (e.g., A/B only) and require notes/photos for any flaws.", "“I don’t have storage space.” → Offer smaller, more frequent bundles and capsule drops (e.g., 15–30 pieces)."]}, "positioning": {"why_us": "Resellers need reliable, on-brand stock without losing hours thrifting and processing. We focus on curated bundles and listing-ready details so you can keep a steady drop cadence, improve margins and reduce returns.", "one_liner": "A friendly sourcing partner helping solo vintage resellers get consistent, photogenic inventory that’s quicker to list and easier to sell.", "differentiators": ["Niche-led bundles built around Pinterestable aesthetics (e.g., workwear, cottagecore, 90s, normcore)", "Batch-level consistency checks (style, condition, size range) to protect your shop look", "Option for listing-ready notes: measurements, condition grading, fabric/era cues", "Drop planning support to keep 5–20 new listings/week without gaps"]}, "channel_plan": {"first_14_days": ["Update LinkedIn headline and About with one-liner + niche bundles + consult CTA.", "Post 3 times/week: (1) drop cohesion tip, (2) margin/time calculation tip, (3) Pinterest keyword + styling tip.", "Publish 1 document post: ‘Listing-Ready Checklist (measurements + condition notes)’.", "Do 10 targeted comments/day on posts from resellers, vintage sellers, Shopify/Etsy communities.", "DM warm engagers with a single question: “What aesthetic are you building and how many items do you need monthly?” then offer the consult."], "primary_channel": "LinkedIn organic", "secondary_channels": ["Pinterest (pin the same drop concepts + keyword boards)", "Instagram (stories for behind-the-scenes and social proof)", "Email (simple weekly ‘drop plan’ digest)"]}, "campaign_ideas": [{"cta": "Comment “AUDIT” for a checklist + booking link.", "hook": "Your pins don’t need more volume—your drops need more cohesion.", "name": "Pinterest-Ready Drop Audit (LinkedIn Mini-Series)", "angle": "Share 3 common reasons vintage drops don’t convert (styling mismatch, inconsistent sizing, weak condition notes) and offer a free 15-min audit."}, {"cta": "DM “CAPSULE” to get the planning template + consult slot.", "hook": "Build a 30-item drop that sells as sets, not singles.", "name": "30-Item Capsule Plan Challenge", "angle": "Explain a simple capsule framework (tops/bottoms/outerwear/accessories) and how to plan sets to lift AOV."}, {"cta": "Book a consultation to calculate your target cost per saleable item.", "hook": "Stop paying with your weekends.", "name": "From Thrift Chaos to Predictable Margins", "angle": "Tell a generic before/after story: time spent thrifting/processing vs curated lots with listing-ready info; invite others to benchmark their time cost."}, {"cta": "Book a consult to set your shop’s grading + measurement SOP.", "hook": "If returns are eating profit, your descriptions are the fix.", "name": "Return-Reduction Clinic", "angle": "Share a short measurement + condition grading standard that reduces disputes; offer to customise it to their shop."}], "success_metrics": {"kpis": ["Consultation bookings per week", "Consultation-to-purchase conversion rate (bundle/lot)", "Inbound DM rate from LinkedIn posts", "Website/booking page conversion rate"], "targets": ["3–8 consult bookings/month from LinkedIn organic", "30–50% consult-to-purchase conversion", "5–10 qualified inbound DMs/week by week 4", "10–20% booking page conversion rate from LinkedIn traffic"]}}', 'icp_strategy_v1', 'gpt-5.2', '2026-01-15 20:03:56.556+00', '2026-01-15 20:03:56.556+00', 'Strategy 1'),
	('1f2ff0eb-cffc-43d9-8bf7-4a1878b4b20b', 'e666668e-4b8a-460c-8db4-63296f9c5855', 'b9f43ab4-a714-432a-843f-4b6bb6ef3891', 'Increase conversions', 'Email', NULL, 'Premium', '{"offer": {"lead_magnet_idea": "Capsule Fit & Outfit Formula Guide (one-page): measuring checklist + 6 outfit formulas for shoots/meetings/remote days.", "recommended_offer": "Premium ‘Capsule Starter’ incentive: free shipping over a sensible threshold or a small store credit for first purchase, positioned as wardrobe-building support (not a discount race).", "landing_page_sections": ["Hero: ‘Shop the Look’ capsule with season/vibe selector", "3 outfit formulas with exact product links", "Fit-confidence module (measurements, ‘fits like’, condition grading)", "Capsule logic: what slots this drop covers + what to pair from your wardrobe", "Social proof (UGC/on-camera looks) + delivery/returns summary", "CTA: Shop capsule / Build my capsule"]}, "ad_assets": null, "messaging": {"value_props": ["Buy fewer, better pieces that work across meetings, shoots, and remote content", "Look intentional on camera with curated palettes, textures, and silhouettes", "Shop consciously with secondhand, without spending weekends browsing", "Spend stays predictable via capsule drops and seasonal edits"], "pain_to_promise": ["Overwhelmed by choice → Tight edits by vibe and season, with outfit-ready pairings", "Fit anxiety online → Clear measurements, ‘fits like’, and easy exchange/credit policy messaging", "Fear of ‘vintage markup’ → Versatility-first styling notes and cost-per-wear framing", "Limited time between gigs → Quick ‘complete the look’ bundles and saved-cart reminders"], "objections_and_rebuttals": ["“Will it fit?” → Provide garment measurements + ‘fits like’ + how-to-measure guide; highlight flexible pieces and tailoring tips", "“Secondhand quality is inconsistent.” → Set quality standards; show close-up condition photos and plain-language grading", "“I don’t want to spend hours styling.” → Include 3 outfit 